import{_ as t,o as a,c as s,a2 as r}from"./chunks/framework.DeNJmwJc.js";const u=JSON.parse('{"title":"Chapter 35 — Registers","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/35-registers.md","filePath":"chapters/35-registers.md"}'),i={name:"chapters/35-registers.md"};function o(d,e,n,l,c,p){return a(),s("div",null,[...e[0]||(e[0]=[r(`<h1 id="chapter-35-—-registers" tabindex="-1">Chapter 35 — Registers <a class="header-anchor" href="#chapter-35-—-registers" aria-label="Permalink to &quot;Chapter 35 — Registers&quot;">​</a></h1><blockquote><p><em>&quot;Registers are Vim&#39;s clipboard on steroids.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐⭐ Intermediate <strong>Estimated Reading Time:</strong> 20 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Registers are named storage locations for text.</p><p>They are Vim&#39;s version of multiple clipboards.</p><hr><h1 id="register-types" tabindex="-1">Register Types <a class="header-anchor" href="#register-types" aria-label="Permalink to &quot;Register Types&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Register</th><th>Name</th><th>Contents</th></tr></thead><tbody><tr><td><code>&quot;&quot;</code></td><td>Unnamed</td><td>Last yank or delete</td></tr><tr><td><code>&quot;0</code></td><td>Yank</td><td>Last yank only</td></tr><tr><td><code>&quot;1</code>-<code>&quot;9</code></td><td>Delete history</td><td>Last 9 deletes</td></tr><tr><td><code>&quot;a</code>-<code>&quot;z</code></td><td>Named</td><td>User-defined</td></tr><tr><td><code>&quot;+</code></td><td>System clipboard</td><td>OS clipboard</td></tr><tr><td><code>&quot;*</code></td><td>Selection</td><td>Mouse selection</td></tr><tr><td><code>&quot;_</code></td><td>Black hole</td><td>Discard text</td></tr><tr><td><code>&quot;=</code></td><td>Expression</td><td>Result of expression</td></tr></tbody></table><hr><h1 id="using-named-registers" tabindex="-1">Using Named Registers <a class="header-anchor" href="#using-named-registers" aria-label="Permalink to &quot;Using Named Registers&quot;">​</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;ayy     →   yank line into register a</span></span>
<span class="line"><span>&quot;ap      →   paste from register a</span></span>
<span class="line"><span>&quot;bdd     →   delete line into register b</span></span>
<span class="line"><span>&quot;bp      →   paste from register b</span></span></code></pre></div><hr><h1 id="the-black-hole-register" tabindex="-1">The Black Hole Register <a class="header-anchor" href="#the-black-hole-register" aria-label="Permalink to &quot;The Black Hole Register&quot;">​</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;_dd     →   delete line, nothing stored</span></span>
<span class="line"><span>&quot;_dw     →   delete word, nothing stored</span></span></code></pre></div><p>Useful when deleting text you don&#39;t want to overwrite the clipboard.</p><hr><h1 id="viewing-registers" tabindex="-1">Viewing Registers <a class="header-anchor" href="#viewing-registers" aria-label="Permalink to &quot;Viewing Registers&quot;">​</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:reg</span></span></code></pre></div><p>Shows all registers.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:reg a b c</span></span></code></pre></div><p>Shows specific registers.</p><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><ul><li><code>&quot;a</code>-<code>&quot;z</code> are named registers — your own clipboards.</li><li><code>&quot;+</code> is the system clipboard.</li><li><code>&quot;_</code> discards text (black hole).</li><li><code>:reg</code> lists all registers.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Yank text into register <code>a</code> and paste it.</li><li>Delete text into register <code>b</code> and paste it.</li><li>Use <code>&quot;+</code> to paste from the system clipboard.</li><li>View all registers with <code>:reg</code>.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./36-marks.html"><strong>Chapter 36 — Marks</strong></a></p><p>Set waypoints in your files for quick navigation.</p>`,34)])])}const g=t(i,[["render",o]]);export{u as __pageData,g as default};
